import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, PieChart, Pie, Cell, Legend, BarChart, Bar 
} from 'recharts';
import './App.css';

const API_BASE_URL = 'http://127.0.0.1:5000/api';
const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

function App() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchEverything = async () => {
      try {
        // Yeni Backend yapımızda tek bir /dashboard/all isteği her şeyi getiriyor
        const res = await axios.get(`${API_BASE_URL}/dashboard/all`);
        setData(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Veri çekme hatası:", err);
        setLoading(false);
      }
    };
    fetchEverything();
  }, []);

  if (loading) return (
    <div style={{display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', flexDirection: 'column'}}>
      <h2 style={{fontFamily: 'sans-serif', color: '#333'}}>📊 InsightFlow Hazırlanıyor...</h2>
      <p>Veriler işleniyor, lütfen bekleyin.</p>
    </div>
  );

  return (
    <div className="App" style={{ backgroundColor: '#f8fafc', minHeight: '100vh', padding: '20px' }}>
      <div className="dashboard-container" style={{ maxWidth: '1200px', margin: '0 auto' }}>

        {/* Başlık Bölümü */}
        <header className="header" style={{ marginBottom: '30px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <h1 style={{ color: '#1e293b', marginBottom: '5px', fontWeight: '800' }}>📊 InsightFlow KDS</h1>
            <p style={{ color: '#64748b', margin: 0 }}>E-Ticaret Karar Destek Sistemi</p>
          </div>
          <div style={{ padding: '8px 16px', backgroundColor: '#dcfce7', borderRadius: '30px' }}>
            <span style={{ color: '#15803d', fontWeight: '600', fontSize: '0.85em' }}>● Sistem Çevrimiçi</span>
          </div>
        </header>

        {/* 1. SATIR: KPI Kartları */}
        <div className="kpi-cards" style={{ display: 'flex', gap: '20px', marginBottom: '30px' }}>
          <KpiCard title="Toplam Gelir" value={`₺${data?.kpis?.total_revenue?.toLocaleString('tr-TR')}`} color="#6366f1" />
          <KpiCard title="Sipariş Sayısı" value={data?.kpis?.total_orders?.toLocaleString('tr-TR')} color="#10b981" />
          <KpiCard title="Aktif Müşteri" value={data?.kpis?.unique_customers?.toLocaleString('tr-TR')} color="#f59e0b" />
          <KpiCard title="Ort. Sepet (AOV)" value={`₺${data?.kpis?.aov?.toLocaleString('tr-TR', { minimumFractionDigits: 2 })}`} color="#8b5cf6" />
        </div>

        {/* 2. SATIR: Grafikler (Trend ve Kategori) */}
        <div className="charts-area" style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '25px', marginBottom: '25px' }}>

          <div style={chartCardStyle}>
            <h3 style={chartTitleStyle}>Aylık Satış Akışı</h3>
            <ResponsiveContainer width="100%" height={300}>
              <LineChart data={data?.trend}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                <YAxis hide />
                <Tooltip contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}} />
                <Line type="monotone" dataKey="value" stroke="#6366f1" strokeWidth={4} dot={{ r: 6, fill: '#6366f1', strokeWidth: 3, stroke: '#fff' }} />
              </LineChart>
            </ResponsiveContainer>
          </div>

          <div style={chartCardStyle}>
            <h3 style={chartTitleStyle}>Kategori Dağılımı</h3>
            <ResponsiveContainer width="100%" height={300}>
              <PieChart>
                <Pie data={data?.categories} dataKey="value" nameKey="name" cx="50%" cy="50%" innerRadius={60} outerRadius={90} paddingAngle={5}>
                  {data?.categories?.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* 3. SATIR: Yeni Bölümler (Scroll Buradan Sonra Devam Ediyor) */}
        <div className="details-area" style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: '25px', marginBottom: '30px' }}>

          {/* En Çok Satanlar Çubuk Grafiği */}
          <div style={chartCardStyle}>
            <h3 style={chartTitleStyle}>En Çok Satan 5 Ürün</h3>
            <ResponsiveContainer width="100%" height={350}>
              <BarChart data={data?.top_products} layout="vertical">
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} axisLine={false} tickLine={false} />
                <Tooltip cursor={{fill: 'transparent'}} />
                <Bar dataKey="value" fill="#6366f1" radius={[0, 10, 10, 0]} barSize={20} />
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* Son İşlemler Tablosu */}
          <div style={chartCardStyle}>
            <h3 style={chartTitleStyle}>Son 10 Sipariş</h3>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9em' }}>
              <thead>
                <tr style={{ textAlign: 'left', color: '#94a3b8', borderBottom: '1px solid #f1f5f9' }}>
                  <th style={{ padding: '12px 8px' }}>Müşteri</th>
                  <th>Ürün</th>
                  <th style={{ textAlign: 'right' }}>Tutar</th>
                </tr>
              </thead>
              <tbody>
                {data?.recent?.map((order, i) => (
                  <tr key={i} style={{ borderBottom: '1px solid #f8fafc' }}>
                    <td style={{ padding: '12px 8px', fontWeight: '500' }}>{order.customer}</td>
                    <td style={{ color: '#64748b' }}>{order.product}</td>
                    <td style={{ textAlign: 'right', fontWeight: '700', color: '#1e293b' }}>₺{order.amount.toLocaleString('tr-TR')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

      </div>
    </div>
  );
}

